// src/components/SeguimientoPedido.js
import React, { useState, useEffect } from 'react';
import { Package, Truck, CheckCircle, MapPin } from 'lucide-react';

const SeguimientoPedido = ({ pedido }) => {
  const [fase, setFase] = useState(1);

  // Simulamos el movimiento del repartidor para la demo
  useEffect(() => {
    const timer = setTimeout(() => setFase(2), 7000); // A los 7s pasa a "En camino"
    const timer2 = setTimeout(() => setFase(3), 15000); // A los 15s pasa a "Entregado"
    return () => { clearTimeout(timer); clearTimeout(timer2); };
  }, []);

  const pasos = [
    { id: 1, label: 'Confirmado', icon: <Package size={20} /> },
    { id: 2, label: 'En camino', icon: <Truck size={20} /> },
    { id: 3, label: 'Entregado', icon: <CheckCircle size={20} /> }
  ];

  return (
    <div style={container}>
      <div style={header}>
        <strong>Pedido #{pedido.id.slice(-5)}</strong>
        <span style={statusLabel}>{pasos[fase-1].label}</span>
      </div>
      
      <div style={stepper}>
        {pasos.map((p) => (
          <div key={p.id} style={{ ...step, color: fase >= p.id ? '#e67e22' : '#cbd5e1' }}>
            <div style={{ ...iconCircle, background: fase >= p.id ? '#e67e22' : '#f1f5f9' }}>
              {React.cloneElement(p.icon, { color: fase >= p.id ? 'white' : '#94a3b8' })}
            </div>
            <span style={label}>{p.label}</span>
          </div>
        ))}
      </div>

      {fase === 2 && (
        <div style={deliveryAlert}>
          <MapPin size={14} />
          <span>El repartidor está cerca de tu ubicación.</span>
        </div>
      )}
    </div>
  );
};

const container = { background: 'white', padding: '15px', borderRadius: '15px', border: '1px solid #e2e8f0', marginBottom: '15px' };
const header = { display: 'flex', justifyContent: 'space-between', marginBottom: '15px', fontSize: '0.9rem' };
const statusLabel = { color: '#e67e22', fontWeight: 'bold' };
const stepper = { display: 'flex', justifyContent: 'space-between' };
const step = { display: 'flex', flexDirection: 'column', alignItems: 'center', flex: 1 };
const iconCircle = { width: '35px', height: '35px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', marginBottom: '5px' };
const label = { fontSize: '0.65rem', fontWeight: 'bold' };
const deliveryAlert = { marginTop: '10px', background: '#f0fdf4', color: '#166534', padding: '8px', borderRadius: '8px', fontSize: '0.75rem', display: 'flex', alignItems: 'center', gap: '5px' };

export default SeguimientoPedido;
